+        let path = entry.path()?;
+        let components = path
+            .components()
+            .map(|component| component.as_os_str())
+            .collect::<Vec<_>>();
+        let Some(registry_index) = components
+            .iter()
+            .position(|component| *component == "registry")
+        else {
