+    let registry = parse_registry_archive(&download_path)
+        .wrap_err("downloaded mise registry archive is invalid")?;
+    #[cfg(windows)]
+    if cache_path.exists() {
+        file::remove_file(cache_path)?;
+    }
+    file::rename(&download_path, cache_path)?;
