+        let tool = parse_registry_tool(&short, &value)
+            .wrap_err_with(|| format!("invalid registry/{short}.toml"))?;
+        entries.insert(short, tool.clone());
+        for alias in tool.aliases {
+            entries.insert((*alias).to_string(), tool.clone());
+        }
+    }
