name: cloudflare-deploy

on:
  release:
    types: [published]
  workflow_dispatch:
    inputs:
      dry_run:
        description: "Run in dry-run mode (no actual deployment)"
        required: false
        default: true
        type: boolean

concurrency:
  group: cloudflare-deploy-${{ github.event_name == 'release' && github.event.release.tag_name || github.ref_name }}

env:
  DRY_RUN: ${{ github.event_name == 'release' && '0' || (github.event_name == 'workflow_dispatch' && (github.event.inputs.dry_run && '1' || '0')) || '1' }}
  MISE_EXPERIMENTAL: 1

jobs:
  deploy-cloudflare:
    runs-on: ubuntu-latest
    timeout-minutes: 30
    if: |
      (github.event_name == 'release' && 
       startsWith(github.event.release.tag_name, 'v') && 
       !github.event.release.prerelease) ||
      github.event_name == 'workflow_dispatch'
    steps:
      - name: Checkout repository
        uses: actions/checkout@9c091bb21b7c1c1d1991bb908d89e4e9dddfe3e0 # v7

      - name: Install mise
        run: |
          curl -fsSL https://mise.run | sh
          echo "$HOME/.local/bin" >> "$GITHUB_PATH"
          ~/.local/bin/mise --version

      - name: Install mise tools
        run: mise install

      - name: Deploy Cloudflare Worker
        run: mise x -- scripts/deploy-worker.sh
        env:
          CLOUDFLARE_ACCESS_KEY_ID: ${{ secrets.CLOUDFLARE_ACCESS_KEY_ID }}
          CLOUDFLARE_API_TOKEN: ${{ secrets.CLOUDFLARE_TOKEN }}
          CLOUDFLARE_SECRET_ACCESS_KEY: ${{ secrets.CLOUDFLARE_SECRET_ACCESS_KEY }}
#!/usr/bin/env bash
set -xeuo pipefail
#MISE depends=["docs:build"]
#MISE dir="docs"
#MISE description="Release documentation site to production or remote"

aws --version
export AWS_REGION=auto
export AWS_ENDPOINT_URL=https://6e243906ff257b965bcae8025c2fc344.r2.cloudflarestorage.com

if [ "${DRY_RUN:-true}" = "true" ]; then
	aws() {
		echo "DRY RUN: aws $*"
	}
fi

if [ $((RANDOM % 30)) -eq 0 ]; then
	# delete old assets only roughly 1/30 times
	# deleting old assets can break the site for people currently on it
	# but it's also good to keep things tidy
	aws s3 rm --recursive s3://mise/assets/
	aws s3 rm --recursive --exclude "*" --include "*.html" s3://mise/
fi

aws s3 cp --recursive --checksum-algorithm CRC32 .vitepress/dist s3://mise/
